#include<bits/stdc++.h>
using namespace std;

int main(){
    int n,ans=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        if(i%4!=0&&i%7!=0){
            string a=to_string(i);
            for(int i=1;i<a.size();i++){
                if((a[i-1]=='4'&&a[i]=='4')||a[i-1]=='7'&&a[i]=='7'){
                    goto T;
                    break;
                }
            }
          ans--;
        }
        T:
        ans++;
    }
    cout<<ans;
    return 0;
}
